html:
{% set doc = doc %}
{% set columns = get_order_sheet_ct_dynamic_columns(doc) %}
{% set ncol = 1 + (columns | length) %}
{% set child_meta = frappe.get_meta("Order Sheet CT") %}
{% set parent_meta = frappe.get_meta(doc.doctype) %}
{% set left_types = ['Data', 'Text', 'Small Text', 'Text Editor', 'Link', 'Long Text', 'Code'] %}
{% set FOOTER_MAP = {"order_qty":"total_quantity","total_carton":"total_cartoon","order_cbm":"total_order_cbm","net_weight":"total_net_weight","gross_weight":"total_gross_weight","total_consumption":"total_consumption"} %}
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="pdfkit-orientation" content="Landscape">
<meta name="pdfkit-page-size" content="A4">
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  /* ── KEY FIX: explicit A4 landscape dimensions for browser preview ── */
  html {
    width: 297mm;
    min-height: 210mm;
  }
  body {
    width: 297mm;
    min-height: 210mm;
    font-family: 'Arial Narrow', Arial, sans-serif;
    font-size: 8.5pt;
    color: #1a1a1a;
    background: #fff;
  }

  @page { size: A4 landscape; margin: 10mm 12mm; }

  @media print {
    html, body { width: 297mm; min-height: 210mm; }
    body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  }

  .page { width: 100%; padding: 10mm 12mm; }

  /* Header */
  .header { display: flex; justify-content: space-between; align-items: flex-start; border-bottom: 3px solid #1a1a2e; padding-bottom: 7px; margin-bottom: 8px; }
  .doc-title { font-size: 20pt; font-weight: 900; letter-spacing: 3px; text-transform: uppercase; color: #1a1a2e; line-height: 1; }
  .doc-name { font-size: 9pt; color: #666; margin-top: 3px; letter-spacing: 1px; }
  .header-right { text-align: right; }

  /* Status badges */
  .status-badge { display: inline-block; padding: 2px 8px; font-size: 7pt; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; border-radius: 2px; }
  .badge-draft     { background: #e0e0e0; color: #555; }
  .badge-submitted { background: #d4edda; color: #155724; }
  .badge-cancelled { background: #f8d7da; color: #721c24; }

  /* Meta table */
  .meta-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; border: 1px solid #c0c0c0; }
  .meta-table td { border-right: 1px solid #c0c0c0; padding: 5px 8px; vertical-align: top; }
  .meta-table td:last-child { border-right: none; }
  .meta-label { font-size: 6pt; text-transform: uppercase; letter-spacing: 0.8px; color: #888; font-weight: 700; margin-bottom: 2px; }
  .meta-value { font-size: 10pt; font-weight: 700; color: #1a1a2e; }

  /* Section heading */
  .section-heading { background: #1a1a2e; color: #fff; font-size: 7pt; text-transform: uppercase; letter-spacing: 1.5px; font-weight: 700; padding: 4px 8px; margin-bottom: 0; }

  /* Order table */
  table.order-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; font-size: 6.8pt; table-layout: auto; }
  table.order-table thead tr { background: #2d3561; }
  table.order-table thead th { padding: 4px 3px; text-align: center; font-size: 6pt; text-transform: uppercase; letter-spacing: 0.4px; font-weight: 700; border: 1px solid #1a1a2e; white-space: nowrap; overflow: hidden; color: #fff; }
  table.order-table thead th.left { text-align: left; }
  table.order-table tbody tr:nth-child(even) { background: #f4f6fb; }
  table.order-table tbody td { padding: 3px; border: 1px solid #d4d8e8; text-align: center; vertical-align: middle; color: #222; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  table.order-table tbody td.left { text-align: left; }
  table.order-table tfoot tr { background: #1a1a2e; }
  table.order-table tfoot td { padding: 4px 3px; border: 1px solid #0d0d1a; text-align: center; font-size: 6.8pt; color: #fff; font-weight: 700; }

  /* Bottom summary tables */
  .bottom-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .bottom-table > tbody > tr > td { width: 50%; vertical-align: top; border: 1px solid #c0c0c0; }
  .bottom-table > tbody > tr > td + td { border-left: none; }

  .box-title { background: #2d3561; color: #fff; font-size: 6.5pt; text-transform: uppercase; letter-spacing: 1px; font-weight: 700; padding: 4px 8px; }

  .inner-table { width: 100%; border-collapse: collapse; }
  .inner-table tr:nth-child(even) td { background: #f4f6fb; }
  .inner-table td { padding: 3px 7px; border-bottom: 1px solid #e0e0e0; font-size: 7.5pt; }
  .inner-table td:first-child { color: #666; font-size: 6.5pt; text-transform: uppercase; letter-spacing: 0.3px; width: 60%; }
  .inner-table td:last-child { font-weight: 700; text-align: right; color: #1a1a2e; }

  /* Instructions */
  .instructions-table { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .instructions-table td { border: 1px solid #c0c0c0; vertical-align: top; }
  .instructions-content { padding: 7px; font-size: 7.5pt; color: #333; min-height: 50px; line-height: 1.5; }

  /* Footer */
  .doc-footer { border-top: 2px solid #1a1a2e; padding-top: 5px; display: flex; justify-content: space-between; font-size: 6.5pt; color: #999; }
</style>
</head>
<body>
<div class="page">

  <!-- Header -->
  <div class="header">
    <div class="header-left">
      <div class="doc-title">Order Sheet</div>
      <div class="doc-name">{{ doc.name }}</div>
    </div>
    <div class="header-right">
      <div style="margin-top:4px;">
        {% if doc.docstatus == 0 %}<span class="status-badge badge-draft">Draft</span>
        {% elif doc.docstatus == 1 %}<span class="status-badge badge-submitted">Submitted</span>
        {% else %}<span class="status-badge badge-cancelled">Cancelled</span>{% endif %}
      </div>
    </div>
  </div>

  <!-- Meta row -->
  <table class="meta-table">
    <tr>
      <td>
        <div class="meta-label">Order No</div>
        <div class="meta-value">{{ doc.order_no or '—' }}</div>
      </td>
      <td>
        <div class="meta-label">Customer</div>
        <div class="meta-value">{{ doc.customer or '—' }}</div>
      </td>
      <td>
        <div class="meta-label">Shipment Date</div>
        <div class="meta-value">{{ frappe.format_date(doc.shipment_date) }}</div>
      </td>
      <td>
        <div class="meta-label">Port of Destination</div>
        <div class="meta-value">{{ doc.port_of_destination or '—' }}</div>
      </td>
    </tr>
  </table>

  <!-- Order lines -->
  <div class="section-heading">Order Details</div>
  <table class="order-table">
    <thead>
      <tr>
        <th style="width:2%;">#</th>
        {% for col in columns %}
        {% set dfh = child_meta.get_field(col.fieldname) %}
        <th class="{% if dfh and dfh.fieldtype in left_types %}left{% endif %}">{{ col.label }}</th>
        {% endfor %}
      </tr>
    </thead>
    <tbody>
      {% for row in doc.order_sheet_ct %}
      <tr>
        <td>{{ loop.index }}</td>
        {% for col in columns %}
        {% set df = child_meta.get_field(col.fieldname) %}
        <td class="{% if df and df.fieldtype in left_types %}left{% endif %}">
          {% set raw = row.get(col.fieldname) %}
          {% if raw is none or raw == '' %}—{% elif df %}{{ frappe.format_value(raw, df) }}{% else %}{{ raw }}{% endif %}
        </td>
        {% endfor %}
      </tr>
      {% else %}
      <tr><td colspan="{{ ncol }}" style="text-align:center;color:#999;padding:10px;">No order lines found.</td></tr>
      {% endfor %}
    </tbody>
    {% if columns and doc.order_sheet_ct %}
    <tfoot>
      <tr>
        <td></td>
        {% for col in columns %}
        <td>
          {% set fk = FOOTER_MAP.get(col.fieldname) %}
          {% if fk %}
            {% set pdf = parent_meta.get_field(fk) %}
            {{ frappe.format_value(doc.get(fk), pdf) }}
          {% else %}—{% endif %}
        </td>
        {% endfor %}
      </tr>
    </tfoot>
    {% endif %}
  </table>

  <!-- Totals: Order + Logistics side by side -->
  <table class="bottom-table">
    <tr>
      <td>
        <div class="box-title">Order Totals</div>
        <table class="inner-table">
          <tr><td>Total Order Qty</td><td>{{ doc.total_order_qty | round(2) if doc.total_order_qty else '0' }}</td></tr>
          <tr><td>Total Planned Qty</td><td>{{ doc.total_planned_qty | round(2) if doc.total_planned_qty else '0' }}</td></tr>
          <tr><td>Total Order Carton</td><td>{{ doc.total_cartoon | round(2) if doc.total_cartoon else '0' }}</td></tr>
          <tr><td>Total Planned Carton</td><td>{{ doc.total_planned_cartoon | round(2) if doc.total_planned_cartoon else '0' }}</td></tr>
          <tr><td>Total Quantity Per Carton</td><td>{{ doc.total_quantity_per_cartoon | round(4) if doc.total_quantity_per_cartoon else '0' }}</td></tr>
        </table>
      </td>
      <td>
        <div class="box-title">Logistics Totals</div>
        <table class="inner-table">
          <tr><td>Total Order CBM</td><td>{{ doc.total_order_cbm | round(4) if doc.total_order_cbm else '0' }}</td></tr>
          <tr><td>Total Planned CBM</td><td>{{ doc.total_planned_cbm | round(4) if doc.total_planned_cbm else '0' }}</td></tr>
          <tr><td>Total Net Weight (KG)</td><td>{{ doc.total_net_weight | round(3) if doc.total_net_weight else '0' }}</td></tr>
          <tr><td>Total Gross Weight (KG)</td><td>{{ doc.total_gross_weight | round(3) if doc.total_gross_weight else '0' }}</td></tr>
        </table>
      </td>
    </tr>
  </table>

  <!-- Instructions full width -->
  <table class="instructions-table">
    <tr>
      <td>
        <div class="box-title">Instructions</div>
        <div class="instructions-content">{{ doc.instructions or '—' }}</div>
      </td>
    </tr>
  </table>

  <!-- Footer -->
  <div class="doc-footer">
    <div>Printed: {{ doc.creation }}</div>
    <div>{% if doc.amended_from %}Amended From: {{ doc.amended_from }}{% endif %}</div>
    <div>{{ doc.name }} &nbsp; Page 1</div>
  </div>

</div>
</body>
</html>
